"""matplotlib.colorbar — colorbar stubs."""

from matplotlib.artist import Artist


class Colorbar:
    def __init__(self, ax, mappable=None, **kwargs):
        self.ax = ax
        self.mappable = mappable
        self.solids = None

    def set_label(self, label, **kwargs): pass
    def set_ticks(self, ticks, **kwargs): pass
    def set_ticklabels(self, ticklabels, **kwargs): pass
    def update_normal(self, mappable): pass
    def remove(self): pass
    def set_alpha(self, alpha): pass

    @property
    def vmin(self): return 0
    @property
    def vmax(self): return 1


class ColorbarBase(Colorbar):
    pass


def make_axes(parents, **kwargs):
    return None, {}


def make_axes_gridspec(parent, **kwargs):
    return None, {}
